const body = $input.first().json;
const action = body.action;
const pr = body.pull_request || {};
const repo = body.repository?.full_name || 'HCI_AI';
const title = pr.title || 'No title';
const url = pr.html_url || '';
const user = pr.user?.login || 'unknown';
const branch = pr.head?.ref || '';
const base = pr.base?.ref || '';

const relevantActions = ['opened', 'merged', 'closed', 'review_requested'];
if (!relevantActions.includes(action)) {
  return [{ json: { skip: true } }];
}

const emoji = action === 'merged' ? '✅' : action === 'opened' ? '🔔' : action === 'closed' ? '🔴' : '👁️';
const notifTitle = `PR ${action.toUpperCase()}: ${repo}`;
const message = `${emoji} #${pr.number}: ${title}\n${branch} → ${base}\nBy: ${user}`;

return [{ json: { skip: false, notifTitle, message, pr_url: url, action } }];
